from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of building‑related triples into a single fluent sentence."""
    if not triples:
        return ""

    # Helper to clean literal strings (remove surrounding quotes)
    def _clean(val: str) -> str:
        return val.strip('"').strip("'")

    # First, build a dictionary: subject -> {predicate: object}
    from collections import defaultdict
    subj_dict = defaultdict(dict)
    for triple in triples:
        subj = triple.subject
        pred = triple.predicate
        obj = _clean(triple.object)
        # keep first occurrence; later duplicates are ignored
        if pred not in subj_dict[subj]:
            subj_dict[subj][pred] = obj

    sentences = []

    # 1️⃣  Handle city‑level information (postalCode, governingBody, leader, etc.)
    # We treat any subject that has at least one of these predicates as a "city" clause.
    city_predicates = {"postalCode", "governingBody", "leader", "capital", "language", "currency", "ethnicGroup"}
    for subj, props in subj_dict.items():
        parts = []
        if "postalCode" in props:
            parts.append(f"has postal code {props['postalCode']}")
        if "governingBody" in props:
            parts.append(f"is governed by {props['governingBody']}")
        if "leader" in props:
            # use a smoother phrasing
            parts.append(f"is led by {props['leader']}")
        if "capital" in props:
            parts.append(f"is the capital {props['capital']}")
        if "language" in props:
            parts.append(f"has language {props['language']}")
        if "currency" in props:
            parts.append(f"uses {props['currency']}")
        if "ethnicGroup" in props:
            parts.append(f"has ethnic group {props['ethnicGroup']}")
        if parts:
            city_sentence = f"{subj}, which " + ", ".join(parts)
            sentences.append(city_sentence)

    # 2️⃣  Handle building‑architect‑origin relationships
    # Find triples where a building has an architect, and optionally the architect has an origin.
    for building, props in subj_dict.items():
        if "architect" in props:
            architect = props["architect"]
            # Look up origin of the architect if present
            origin = subj_dict.get(architect, {}).get("origin")
            if origin:
                architect_phrase = f"{architect} from {origin}"
            else:
                architect_phrase = architect
            clause = f"{architect_phrase} designed {building}"
            # Add extra building details if available
            extra_parts = []
            if "location" in props:
                extra_parts.append(f"is located in {props['location']}")
            if "height" in props:
                extra_parts.append(f"has a height of {props['height']} metres")
            if "floorCount" in props:
                extra_parts.append(f"has {props['floorCount']} floors")
            if "buildingType" in props:
                extra_parts.append(f"is a {props['buildingType']}")
            if extra_parts:
                clause += " and " + " and ".join(extra_parts)
            sentences.append(clause)

    # 3️⃣  Fallback

